describe("Date.prototype.toLocaleString with timezone",()=>{it("should support timeZone option",()=>{let e=new Date("2022-03-02T15:45:34Z"),t=e.toLocaleString("en-US",{timeZone:"America/Denver"}),o=e.toLocaleString("en-US",{timeZone:"Asia/Tokyo"});expect(t).toContain("8:45"),expect(o).toContain("3/3")}),it("should work without timezone option",()=>{let t=new Date("2022-03-02T15:45:34Z").toLocaleString();expect(typeof t).toBe("string"),expect(t.length).toBeGreaterThan(0)}),it("should handle Invalid Date",()=>{let t=new Date("invalid").toLocaleString("en-US",{timeZone:"UTC"});expect(t).toBe("Invalid Date")})});
